#include <bits/stdc++.h>
#define int long long
using namespace std;
const int INF = INT_MAX , N = 3005;
vector < pair < int , int > > g[ N ];
priority_queue< pair< int , int > > pq;
int dis[ N ] , vis[ N ];
int n , m , s;
int s1 , t1 , s2 , t2;
int ans = INT_MAX;
void dij() {
	memset( vis , false , sizeof( vis ) );
	for( int i = 0 ; i <= n ; i++ )
		dis[ i ] = INF;
	dis[ s ] = 0;
	pq.push( { 0 , s } );
	while( !pq.empty() ) {
		int mi = pq.top().second;
		pq.pop();
		if( vis[ mi ] )
			continue;
		vis[ mi ] = 1;
		for( auto i : g[ mi ] ) {
			int a = i.first;
			int b = i.second;
			if( dis[ a ] > dis[ mi ] + b ) {
				dis[ a ] = dis[ mi ] + b;
				pq.push( { -dis[ a ] , a } );
			}
		}
	}
} 
signed main() {
	cin >> n >> m;
	for( int i = 1 ; i <= m ; i++ ) {
		int x , y;
		cin >> x >> y;
		g[ x ].push_back( { y , 1 } );
		g[ y ].push_back( { x , 1 } );
	}
	cin >> s1 >> t1 >> s2 >> t2;
	for( int i = 1 ; i <= n ; i++ ) {
		s = i;
		dij( );
		if( dis[ 1 ] + dis[ s1 ] <= t1 && dis[ 1 ] + dis[ s2 ] <= t2 )
			ans = min( ans , dis[ 1 ] + dis[ s1 ] + dis[ s2 ] );
	}
	if( ans == INT_MAX ) {
		cout << "-1";
		return 0;
	}
	cout << m - ans;
	return 0;
}
